"""
Access Control List (ACL) Implementation for OS Protection
Each object maintains a list of (domain, rights) pairs
"""
from typing import Dict, Set, List, Tuple

class ACL:
 """Access Control List - stores permissions per object"""

 def __init__(self):
 # Dictionary: object_name -> dict of {domain: set of rights}
 self.permissions: Dict[str, Dict[str, Set[str]]] = {}

 def add_object(self, object_name: str):
 """Create a new object with empty ACL"""
 if object_name not in self.permissions:
 self.permissions[object_name] = {}

 def grant_access(self, domain: str, object_name: str, *rights: str):
 """Grant specific rights to a domain for an object"""
 if object_name not in self.permissions:
 self.add_object(object_name)

 if domain not in self.permissions[object_name]:
 self.permissions[object_name][domain] = set()

 self.permissions[object_name][domain].update(rights)

 def revoke_access(self, domain: str, object_name: str, *rights: str):
 """Revoke specific rights from a domain for an object"""
 if object_name in self.permissions and domain in self.permissions[object_name]:
 self.permissions[object_name][domain].difference_update(rights)

 # Clean up empty rights sets
 if not self.permissions[object_name][domain]:
 del self.permissions[object_name][domain]

 def check_access(self, domain: str, object_name: str, required_right: str) -> bool:
 """Check if a domain has a specific right on an object"""
 if object_name not in self.permissions:
 return False

 if domain not in self.permissions[object_name]:
 return False

 return required_right in self.permissions[object_name][domain]

 def get_acl(self, object_name: str) -> Dict[str, Set[str]]:
 """Get the full ACL for an object"""
 return self.permissions.get(object_name, {})

 def display(self):
 """Display all ACLs"""
 print("=== Access Control Lists ===")
 for obj, acls in self.permissions.items():
 print(f"\nObject: {obj}")
 for domain, rights in acls.items():
 print(f" {domain}: {', '.join(rights)}")


# Demonstration
if __name__ == "__main__":
 acl = ACL()

 # Create objects
 acl.add_object("file1.txt")
 acl.add_object("file2.txt")
 acl.add_object("printer")

 # Grant access (simulating the Access Matrix columns)
 acl.grant_access("domain_D1", "file1.txt", "read", "write")
 acl.grant_access("domain_D1", "file2.txt", "read")
 acl.grant_access("domain_D2", "file1.txt", "read")
 acl.grant_access("domain_D2", "printer", "print")
 acl.grant_access("domain_D3", "file2.txt", "read", "write")
 acl.grant_access("domain_D4", "file1.txt", "read", "write")
 acl.grant_access("domain_D4", "printer", "print")

 acl.display()

 # Test access checks
 print("\n=== Access Checks ===")
 print(f"D1 can read file1.txt: {acl.check_access('domain_D1', 'file1.txt', 'read')}")
 print(f"D1 can write file1.txt: {acl.check_access('domain_D1', 'file1.txt', 'write')}")
 print(f"D2 can write file1.txt: {acl.check_access('domain_D2', 'file1.txt', 'write')}")
 print(f"D2 can print: {acl.check_access('domain_D2', 'printer', 'print')}")

 # Revoke access
 print("\n=== After Revoking write from D1 on file1.txt ===")
 acl.revoke_access("domain_D1", "file1.txt", "write")
 print(f"D1 can write file1.txt: {acl.check_access('domain_D1', 'file1.txt', 'write')}")

"""
Capability Lists Implementation for OS Protection
Each domain maintains a list of (object, rights) capabilities it holds
"""
from typing import Dict, Set, List

class CapabilityList:
 """Capability List - stores permissions per domain (row-based)"""

 def __init__(self):
 # Dictionary: domain -> dict of {object: set of rights}
 self.capabilities: Dict[str, Dict[str, Set[str]]] = {}

 def create_domain(self, domain: str):
 """Create a new domain with empty capabilities"""
 if domain not in self.capabilities:
 self.capabilities[domain] = {}

 def grant_capability(self, domain: str, object_name: str, *rights: str):
 """Grant a capability to a domain for an object"""
 if domain not in self.capabilities:
 self.create_domain(domain)

 if object_name not in self.capabilities[domain]:
 self.capabilities[domain][object_name] = set()

 self.capabilities[domain][object_name].update(rights)

 def revoke_capability(self, domain: str, object_name: str, *rights: str):
 """Revoke specific rights from a domain's capability"""
 if domain in self.capabilities and object_name in self.capabilities[domain]:
 self.capabilities[domain][object_name].difference_update(rights)

 if not self.capabilities[domain][object_name]:
 del self.capabilities[domain][object_name]

 def check_capability(self, domain: str, object_name: str, required_right: str) -> bool:
 """Check if domain has the required capability"""
 if domain not in self.capabilities:
 return False

 if object_name not in self.capabilities[domain]:
 return False

 return required_right in self.capabilities[domain][object_name]

 def get_all_rights(self, domain: str) -> Dict[str, Set[str]]:
 """Get all capabilities for a domain (all objects it can access)"""
 return self.capabilities.get(domain, {})

 def transfer_capability(self, from_domain: str, to_domain: str, 
 object_name: str, *rights: str):
 """Transfer specific rights from one domain to another"""
 # Check if source has the rights
 if not self.check_capability(from_domain, object_name, list(rights)[0] if rights else ""):
 return False

 # Grant to destination
 self.grant_capability(to_domain, object_name, *rights)
 return True

 def display(self):
 """Display all capability lists"""
 print("=== Capability Lists ===")
 for domain, caps in self.capabilities.items():
 print(f"\nDomain: {domain}")
 for obj, rights in caps.items():
 print(f" -> {obj}: {', '.join(rights)}")


class Capability:
 """Represents a single capability (ticket/key)"""

 def __init__(self, object_name: str, rights: Set[str]):
 self.object_name = object_name
 self.rights = rights

 def __repr__(self):
 return f"Capability({self.object_name}, {self.rights})"


# Demonstration
if __name__ == "__main__":
 cap_list = CapabilityList()

 # Create domains with capabilities (matching the Access Matrix rows)
 cap_list.grant_capability("domain_D1", "file1.txt", "read", "write")
 cap_list.grant_capability("domain_D1", "file2.txt", "read")
 cap_list.grant_capability("domain_D2", "file1.txt", "read")
 cap_list.grant_capability("domain_D2", "printer", "print")
 cap_list.grant_capability("domain_D3", "file2.txt", "read", "write")
 cap_list.grant_capability("domain_D4", "file1.txt", "read", "write")
 cap_list.grant_capability("domain_D4", "printer", "print")

 cap_list.display()

 # Test capability checks
 print("\n=== Capability Checks ===")
 print(f"D1 has read on file1.txt: {cap_list.check_capability('domain_D1', 'file1.txt', 'read')}")
 print(f"D3 has write on file2.txt: {cap_list.check_capability('domain_D3', 'file2.txt', 'write')}")
 print(f"D2 has print on printer: {cap_list.check_capability('domain_D2', 'printer', 'print')}")

 # Show all rights for a domain
 print(f"\n=== All rights for domain_D4 ===")
 print(cap_list.get_all_rights("domain_D4"))

 # Demonstrate capability transfer
 print("\n=== Capability Transfer ===")
 cap_list.grant_capability("domain_D2", "file2.txt", "read") # Add first
 print(f"Before transfer - D2 file2.txt: {cap_list.get_all_rights('domain_D2')}")

 cap_list.transfer_capability("domain_D3", "domain_D2", "file2.txt", "write")
 print(f"After transfer - D2 file2.txt: {cap_list.get_all_rights('domain_D2')}")

/*
 * Access Matrix Implementation in C
 * Demonstrates protection mechanisms in Operating Systems
 * Rows = Domains, Columns = Objects
 */

#include <stdio.h>
#include <stdbool.h>
#include <string.h>
#include <stdlib.h>

#define MAX_DOMAINS 10
#define MAX_OBJECTS 10
#define MAX_RIGHTS 5
#define MAX_NAME_LENGTH 32

// Structure to represent a right
typedef struct {
 char name[MAX_NAME_LENGTH];
} Right;

// Structure for a single cell in the access matrix
typedef struct {
 bool has_rights; // Whether any rights exist
 bool read;
 bool write;
 bool execute;
 bool print;
} AccessRights;

// The Access Matrix
typedef struct {
 char domain_names[MAX_DOMAINS][MAX_NAME_LENGTH];
 char object_names[MAX_OBJECTS][MAX_NAME_LENGTH];
 AccessRights matrix[MAX_DOMAINS][MAX_OBJECTS];
 int domain_count;
 int object_count;
} AccessMatrix;

// Initialize the access matrix
void init_matrix(AccessMatrix *am) {
 am->domain_count = 0;
 am->object_count = 0;

 // Initialize all cells to no rights
 for (int i = 0; i < MAX_DOMAINS; i++) {
 for (int j = 0; j < MAX_OBJECTS; j++) {
 am->matrix[i][j].has_rights = false;
 am->matrix[i][j].read = false;
 am->matrix[i][j].write = false;
 am->matrix[i][j].execute = false;
 am->matrix[i][j].print = false;
 }
 }
}

// Add a domain to the matrix
int add_domain(AccessMatrix *am, const char *domain_name) {
 if (am->domain_count >= MAX_DOMAINS) {
 return -1; // Full
 }
 strncpy(am->domain_names[am->domain_count], domain_name, MAX_NAME_LENGTH - 1);
 return am->domain_count++;
}

// Add an object to the matrix
int add_object(AccessMatrix *am, const char *object_name) {
 if (am->object_count >= MAX_OBJECTS) {
 return -1; // Full
 }
 strncpy(am->object_names[am->object_count], object_name, MAX_NAME_LENGTH - 1);
 return am->object_count++;
}

// Find domain index
int find_domain(AccessMatrix *am, const char *domain_name) {
 for (int i = 0; i < am->domain_count; i++) {
 if (strcmp(am->domain_names[i], domain_name) == 0) {
 return i;
 }
 }
 return -1;
}

// Find object index
int find_object(AccessMatrix *am, const char *object_name) {
 for (int i = 0; i < am->object_count; i++) {
 if (strcmp(am->object_names[i], object_name) == 0) {
 return i;
 }
 }
 return -1;
}

// Grant access (add a right)
bool grant_access(AccessMatrix *am, const char *domain, 
 const char *object, const char *right) {
 int di = find_domain(am, domain);
 int oi = find_object(am, object);

 if (di == -1 || oi == -1) {
 return false;
 }

 am->matrix[di][oi].has_rights = true;

 if (strcmp(right, "read") == 0) {
 am->matrix[di][oi].read = true;
 } else if (strcmp(right, "write") == 0) {
 am->matrix[di][oi].write = true;
 } else if (strcmp(right, "execute") == 0) {
 am->matrix[di][oi].execute = true;
 } else if (strcmp(right, "print") == 0) {
 am->matrix[di][oi].print = true;
 }

 return true;
}

// Check if access is permitted
bool check_access(AccessMatrix *am, const char *domain, 
 const char *object, const char *right) {
 int di = find_domain(am, domain);
 int oi = find_object(am, object);

 if (di == -1 || oi == -1) {
 return false;
 }

 if (strcmp(right, "read") == 0) {
 return am->matrix[di][oi].read;
 } else if (strcmp(right, "write") == 0) {
 return am->matrix[di][oi].write;
 } else if (strcmp(right, "execute") == 0) {
 return am->matrix[di][oi].execute;
 } else if (strcmp(right, "print") == 0) {
 return am->matrix[di][oi].print;
 }

 return false;
}

// Display the access matrix
void display_matrix(AccessMatrix *am) {
 printf("\n=== Access Matrix ===\n\n");

 // Print header with object names
 printf("%-12s", "Domain");
 for (int j = 0; j < am->object_count; j++) {
 printf("%-15s", am->object_names[j]);
 }
 printf("\n");

 // Print separator
 for (int j = 0; j < am->object_count + 1; j++) {
 printf("%-15s", "-------------");
 }
 printf("\n");

 // Print each domain's row
 for (int i = 0; i < am->domain_count; i++) {
 printf("%-12s", am->domain_names[i]);
 for (int j = 0; j < am->object_count; j++) {
 char rights[64] = "";
 if (am->matrix[i][j].read) strcat(rights, "r");
 if (am->matrix[i][j].write) strcat(rights, "w");
 if (am->matrix[i][j].execute) strcat(rights, "x");
 if (am->matrix[i][j].print) strcat(rights, "p");
 if (rights[0] == '\0') strcpy(rights, "-");
 printf("%-15s", rights);
 }
 printf("\n");
 }
}

// Demonstrate Principle of Least Privilege check
void demonstrate_least_privilege(AccessMatrix *am, const char *domain, 
 const char *object, const char *requested_op) {
 printf("\n[Principle of Least Privilege Check]\n");
 printf("Domain: %s\n", domain);
 printf("Object: %s\n", object);
 printf("Requested operation: %s\n", requested_op);

 if (check_access(am, domain, object, requested_op)) {
 printf("Result: ACCESS GRANTED - Domain has minimum required privilege\n");
 } else {
 printf("Result: ACCESS DENIED - Insufficient privileges\n");
 }
}

int main() {
 AccessMatrix am;
 init_matrix(&am);

 // Add domains
 add_domain(&am, "D1_User");
 add_domain(&am, "D2_User");
 add_domain(&am, "D3_Admin");
 add_domain(&am, "D4_Guest");

 // Add objects
 add_object(&am, "file1.txt");
 add_object(&am, "file2.txt");
 add_object(&am, "printer");
 add_object(&am, "database");

 // Grant access (populate the matrix)
 grant_access(&am, "D1_User", "file1.txt", "read");
 grant_access(&am, "D1_User", "file1.txt", "write");
 grant_access(&am, "D1_User", "file2.txt", "read");

 grant_access(&am, "D2_User", "file1.txt", "read");
 grant_access(&am, "D2_User", "printer", "print");

 grant_access(&am, "D3_Admin", "file1.txt", "read");
 grant_access(&am, "D3_Admin", "file1.txt", "write");
 grant_access(&am, "D3_Admin", "file2.txt", "read");
 grant_access(&am, "D3_Admin", "file2.txt", "write");
 grant_access(&am, "D3_Admin", "printer", "print");
 grant_access(&am, "D3_Admin", "database", "read");
 grant_access(&am, "D3_Admin", "database", "write");

 grant_access(&am, "D4_Guest", "file1.txt", "read");
 grant_access(&am, "D4_Guest", "printer", "print");

 // Display the matrix
 display_matrix(&am);

 // Test access checks
 printf("\n=== Access Verification ===\n");
 printf("D1 can read file1.txt: %s\n", 
 check_access(&am, "D1_User", "file1.txt", "read") ? "YES" : "NO");
 printf("D1 can write file1.txt: %s\n", 
 check_access(&am, "D1_User", "file1.txt", "write") ? "YES" : "NO");
 printf("D2 can read file2.txt: %s\n", 
 check_access(&am, "D2_User", "file2.txt", "read") ? "YES" : "NO");
 printf("D4 can access database: %s\n", 
 check_access(&am, "D4_Guest", "database", "read") ? "YES" : "NO");

 // Demonstrate least privilege
 demonstrate_least_privilege(&am, "D4_Guest", "printer", "print");
 demonstrate_least_privilege(&am, "D4_Guest", "database", "write");

 return 0;
}
